create table dirkspzm32.s_erp_send_bew (
    firma_nr             number(3, 0) not null enable,
    herkunft             varchar2(3 char) not null enable,
    tabelle              varchar2(28 char),
    auf_id               number(*, 0),
    status               varchar2(3 char) not null enable,
    aktion               varchar2(3 char) not null enable,
    leitzahl             number(*, 5),
    fa_ag                number(*, 0),
    fa_upos              number(*, 0),
    ma_status            varchar2(1 char),
    ma_s_grund           number(3, 0),
    ma_id                varchar2(10 char),
    lte_nr               varchar2(20 char),
    lhm_nr               varchar2(20 char),
    lagerort             varchar2(50 char),
    zlagerort            varchar2(50 char),
    menge                number(*, 3),
    menge_b              number(*, 3),
    schrott              number(*, 3),
    r_menge              number(*, 3),
    r_menge_b            number(*, 3),
    r_schrott            number(*, 3),
    me                   varchar2(3 char),
    stoerzeit_ist        number(*, 12),
    ruestzeit_ist        number(*, 12),
    prodzeit_ist         number(*, 12),
    ext_tour             varchar2(20 char),
    vorgang_id           number(*, 0),
    ext_auftrag          number(*, 5),
    ext_pos_nr           number(*, 0),
    ext_upos_nr          number(*, 0),
    ext_lief_nr          varchar2(20 char),
    ext_lief_pos         varchar2(5 char),
    ext_best_nr          varchar2(20 char),
    ext_best_pos         varchar2(5 char),
    charge               varchar2(60 char),
    serie                varchar2(20 char),
    arbeitsplatz_id      varchar2(20 char),
    ist_bestand          number(*, 5),
    artikel              varchar2(30 char),
    b_datum              varchar2(19 char),
    bew_id               number(*, 0) not null enable,
    brutto_kg            number(*, 6),
    ret_code             varchar2(20 char),
    cycle                number(*, 5),
    b_date               date,
    lief_nr              varchar2(20 char),
    komm_q_lte_id        varchar2(20 char),
    komm_z_lte_id        varchar2(20 char),
    komm_q_lhm_id        varchar2(20 char),
    komm_z_lhm_id        varchar2(20 char),
    komm_q_rest_lte      number(*, 5),
    komm_q_rest_lhm      number(*, 5),
    aktion_host          varchar2(20 char),
    lagerplatz           varchar2(30 char),
    zlagerplatz          varchar2(30 char),
    fehler_code          number(*, 5),
    fehler_text          varchar2(2500 char),
    calcdatum            date,
    geb_typ_q            varchar2(20 char),
    geb_typ_z            varchar2(20 char),
    nio_text             varchar2(40 char),
    wickelprogramm       varchar2(4 char),
    inventurdifferenz    number(*, 5),
    ext_host_referenz    varchar2(20 char),
    labor_status         varchar2(1 char),
    lam_sel1             varchar2(30 char),
    lam_sel2             varchar2(30 char),
    lam_sel3             varchar2(30 char),
    lam_sel4             varchar2(30 char),
    lam_sel5             varchar2(30 char),
    lam_sel6             varchar2(30 char),
    lam_sel7             varchar2(30 char),
    lam_sel8             varchar2(30 char),
    lam_sel9             varchar2(30 char),
    lam_sel10            varchar2(30 char),
    lte_name             varchar2(22 char),
    order_pos_auf_id     number(*, 0),
    pruef_plan_nummern   varchar2(1000 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    ruest_zeit_erf       number(*, 12),
    prod_zeit_erf        number(*, 12)
);

alter table dirkspzm32.s_erp_send_bew
    add constraint pk_s_erp_send_bew primary key ( bew_id )
        using index enable;


